#!/usr/bin/env python3
"""
PicoClaw v4.0 — Self-Extracting Deployment (CORRECTED)
Run: python3 deploy_picoclaw_v4.py
"""
import base64, os
from pathlib import Path

PICO = Path.home() / '.picoclaw'
SKILLS = PICO / 'agent_core' / 'skills'
MEMORY = PICO / 'memory'

SKILLS.mkdir(parents=True, exist_ok=True)
MEMORY.mkdir(parents=True, exist_ok=True)

FILES = {}
FILES['self_diagnosis.py'] = {'path': str(SKILLS / 'self_diagnosis.py'), 'b64': ''}
FILES['reasoning_loop.py'] = {'path': str(SKILLS / 'reasoning_loop.py'), 'b64': ''}
FILES['north_star_revenue_integration.py'] = {'path': str(SKILLS / 'north_star_revenue_integration.py'), 'b64': ''}

print("PICOCLAW v4.0 SELF-EXTRACTION (CORRECTED)")
print("=" * 50)

for name, data in FILES.items():
    content = base64.b64decode(data["b64"])
    Path(data["path"]).write_bytes(content)
    print("  deployed: " + name)

# Init memory logs
for f in ["reasoning_log.jsonl", "revenue_log.jsonl", "skill_suggestions.jsonl"]:
    (MEMORY / f).touch()
    print("  initialized: " + f)

# Update local_tools.json
import json
lt_path = PICO / "config" / "local_tools.json"
if lt_path.exists():
    lt = json.loads(lt_path.read_text())
else:
    lt = {"schema_version": "1.0", "hub_node": "termux-primary", "assignment_policy": "capability_match", "tools": {}, "spoke_registry": {}, "unassigned_queue": []}

new_tools = {
    "self_diagnosis": {"assigned_to": "hub", "capabilities_required": ["python3", "file_read", "file_write"], "priority": 0, "failover_to_hub": False},
    "reasoning_loop": {"assigned_to": "hub", "capabilities_required": ["python3", "file_read", "file_write"], "priority": 0, "failover_to_hub": False},
    "north_star_revenue_integration": {"assigned_to": "hub", "capabilities_required": ["python3", "file_read", "file_write"], "priority": 0, "failover_to_hub": False}
}
for n, c in new_tools.items():
    if n not in lt["tools"]:
        lt["tools"][n] = c
        print("  registered: " + n)

lt_path.write_text(json.dumps(lt, indent=2))

print("\n" + "=" * 50)
print("DEPLOYMENT COMPLETE")
print("\nVerify with:")
print("  python3 ~/.picoclaw/agent_core/skills/self_diagnosis.py")
print("  python3 ~/.picoclaw/agent_core/skills/reasoning_loop.py --reflect")
print("  python3 ~/.picoclaw/agent_core/skills/north_star_revenue_integration.py")